mapper.select:
WITH RECURSIVE ProgramTree AS ( -- 1. ANCHOR MEMBER (Starts the recursion with the root nodes) select p.co_id, p.pgm_id, p.pgm_cd, p.pgm_tp_cd, p.prnt_pgm_id, p.pgm_nm, p.dsp_order, p.pgm_rmk, p.use_flg, p.upd_dt, p.upd_usr_id, 1 AS level, CAST(p.pgm_id AS text) AS tree_key, LPAD(CAST(p.dsp_order AS TEXT), 3, '0') AS tree_path FROM com_pgm p WHERE -- Find the top-level programs (roots) p.prnt_pgm_id IS NULL and p.co_id = #{coId}
UNION ALL
-- 2. RECURSIVE MEMBER (Finds children and continues until no more nodes are found) select child.co_id, child.pgm_id, child.pgm_cd, child.pgm_tp_cd, child.prnt_pgm_id, child.pgm_nm, child.dsp_order, child.pgm_rmk, child.use_flg, child.upd_dt, child.upd_usr_id, parent.level + 1 AS level, parent.tree_key || '-' || CAST(child.pgm_id AS text), -- Extend the sort path by appending the child's padded order value parent.tree_path || '-' || LPAD(CAST(child.dsp_order AS TEXT), 3, '0') FROM com_pgm child INNER JOIN ProgramTree parent ON (child.prnt_pgm_id = parent.pgm_id and child.co_id = parent.co_id) ) -- 3. FINAL SELECTION AND ORDERING select co_id, pgm_id, pgm_cd, pgm_tp_cd, pgm_nm, prnt_pgm_id, dsp_order, pgm_rmk, use_flg, upd_dt, upd_usr_id, level, tree_key, --LPAD('', (level - 1) * 4, ' ') || '-> ' || pgm_nm AS tree_display, -- Creates a visual indentation based on the level for better readability tree_path FROM ProgramTree where 1=1 and co_id = #{coId}
AND PGM_ID = #{pgmId}
AND PGM_CD = #{pgmCd}
AND PGM_NM ILIKE '%' || #{pgmNm} || '%'
AND PGM_TP_CD = #{pgmTpCd}
AND USE_FLG = #{useFlg}
ORDER BY tree_path;

SELECT PGM.CO_ID, PGM.PGM_ID, PGM.PGM_CD, PGM.PGM_NM, PGM.PGM_TP_CD, PGM.PRNT_PGM_ID, PGM.DSP_ORDER, PGM.PGM_RMK, PGM.USE_FLG, PGM.CRE_DT, PGM.CRE_USR_ID, PGM.UPD_DT, PGM.UPD_USR_ID FROM COM_PGM PGM WHERE 1=1 AND PGM.CO_ID = #{coId}
AND PGM.PGM_ID = #{pgmId}
AND PGM.PGM_CD = #{pgmCd}
AND PGM.PGM_NM ILIKE '%' || #{pgmNm} || '%'
AND PGM.PGM_TP_CD = #{pgmTpCd}
AND PGM.USE_FLG = #{useFlg}
LIMIT 1

